import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node

    arrival_times = np.zeros(len(distance_matrix))
    for i, truck_node in enumerate(truck_nodes):
        if truck_node != depot_node:
            travel_time = distance_matrix[truck_node, :]
            arrival_times += np.where(travel_time > 0, travel_time, np.inf)

    inverse_timing_factor = 1 / (1 + arrival_times)  # Higher priority to less congested timings

    scores = np.array([
        distance_matrix[current_node, node] * inverse_timing_factor[node] if node in unvisited_nodes else float('inf')
        for node in range(len(distance_matrix))
    ])

    next_node = np.argmin(scores)
    return next_node
